import { cn } from '@utils/cn';
import { getColor } from '@utils/helper';
import QRCode from 'qrcode';
import RefreshCw from 'lucide-solid/icons/refresh-cw';
import CheckCircle from 'lucide-solid/icons/check-circle';
import Loader from 'lucide-solid/icons/loader';
import { Component, createEffect, createUniqueId, mergeProps, onCleanup, Show } from 'solid-js';
import type { QrCodeProps } from './qr-code.types';

const DEFAULT_PROPS = {
  size: 160,
  color: '#000000',
  bgColor: '#ffffff',
  errorLevel: 'M' as const,
  status: 'active' as const,
  expiredText: 'QR code expired',
  accentColor: 'primary' as const,
};

async function drawQr(
  canvas: HTMLCanvasElement,
  value: string,
  opts: {
    size: number;
    color: string;
    bgColor: string;
    errorLevel: 'L' | 'M' | 'Q' | 'H';
  },
): Promise<void> {
  await QRCode.toCanvas(canvas, value || ' ', {
    width: opts.size,
    margin: 2,
    color: {
      dark: opts.color,
      light: opts.bgColor,
    },
    errorCorrectionLevel: opts.errorLevel,
  });
}

function drawLogo(
  canvas: HTMLCanvasElement,
  logo: NonNullable<QrCodeProps['logo']>,
  size: number,
): void {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = function onLogoLoad() {
    const logoW = logo.width ?? size * 0.2;
    const logoH = logo.height ?? logoW;
    const pad = logo.padding ?? 4;
    const radius = logo.borderRadius ?? 4;
    const bg = logo.background ?? '#ffffff';

    const bgW = logoW + pad * 2;
    const bgH = logoH + pad * 2;
    const x = (size - bgW) / 2;
    const y = (size - bgH) / 2;

    // Draw background rect with rounded corners
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + bgW - radius, y);
    ctx.quadraticCurveTo(x + bgW, y, x + bgW, y + radius);
    ctx.lineTo(x + bgW, y + bgH - radius);
    ctx.quadraticCurveTo(x + bgW, y + bgH, x + bgW - radius, y + bgH);
    ctx.lineTo(x + radius, y + bgH);
    ctx.quadraticCurveTo(x, y + bgH, x, y + bgH - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
    ctx.fillStyle = bg;
    ctx.fill();

    // Draw logo image centered inside background
    ctx.drawImage(img, x + pad, y + pad, logoW, logoH);
  };
  img.src = logo.src;
}

export const QrCode: Component<QrCodeProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);
  const id = createUniqueId();
  let canvasRef: HTMLCanvasElement | undefined;

  createEffect(function renderQrCode() {
    if (!canvasRef) return;

    // Snapshot all reactive values synchronously — reads inside .then() would
    // occur outside the reactive computation and throw "Effects is null".
    const canvas = canvasRef;
    const value = p.value;
    const size = p.size;
    const color = p.color;
    const bgColor = p.bgColor;
    const errorLevel = p.errorLevel;
    const logo = p.logo;

    drawQr(canvas, value, { size, color, bgColor, errorLevel }).then(function onQrDrawn() {
      if (logo) {
        drawLogo(canvas, logo, size);
      }
    });
  });

  return (
    <div
      id={id}
      class={cn('qr01', p.class?.root)}
      style={{ width: `${p.size}px`, height: `${p.size}px` }}
    >
      {/* The QR canvas */}
      <canvas
        ref={canvasRef}
        class={cn('qr02', p.class?.canvas)}
        width={p.size}
        height={p.size}
        aria-label={`QR code for: ${p.value}`}
      />

      {/* Loading overlay */}
      <Show when={p.status === 'loading'}>
        <div class={cn('qr03', getColor(p.accentColor), p.class?.overlay)}>
          <Loader class={cn('qr04 animate-spin', p.class?.overlayIcon)} size={p.size * 0.22} />
        </div>
      </Show>

      {/* Expired overlay */}
      <Show when={p.status === 'expired'}>
        <div class={cn('qr03 qr05', getColor(p.accentColor), p.class?.overlay)}>
          <button
            class={cn('qr06', p.class?.overlayIcon)}
            onClick={p.onRefresh}
            aria-label="Refresh QR code"
          >
            <RefreshCw size={p.size * 0.22} />
          </button>
          <span class={cn('qr07', p.class?.overlayText)}>{p.expiredText}</span>
        </div>
      </Show>

      {/* Scanned overlay */}
      <Show when={p.status === 'scanned'}>
        <div class={cn('qr03', getColor('success'), p.class?.overlay)}>
          <CheckCircle class={cn('qr04', p.class?.overlayIcon)} size={p.size * 0.22} />
        </div>
      </Show>
    </div>
  );
};
